import { useState, useEffect, useCallback, useRef } from "react";
import {
  LEVELS, TIMERS, ALL_RADICALS, ALL_CHARS,
  filterChars, randomRadicals,
  generateQuizPool, generateQuestion, generateChallengePool,
  parseMarkdownImport,
} from "./data/gameEngine";

// ─── 格式化時間 ──────────────────────────────────────────────────
function formatTime(sec) {
  if (sec <= 0) return "0:00";
  const m = Math.floor(sec / 60);
  const s = sec % 60;
  return `${m}:${s.toString().padStart(2, "0")}`;
}

// ═══════════════════════════════════════════════════════════════════
export default function HanziApp() {
  // ─── 狀態 ─────────────────────────────────────────────────────
  const [screen, setScreen] = useState("home");
  const [level, setLevel] = useState(1);
  const [selectedRadicals, setSelectedRadicals] = useState(() => randomRadicals(5, 1));
  const [radicalSearch, setRadicalSearch] = useState("");
  const [timerValue, setTimerValue] = useState(180);
  const [showChallengeModal, setShowChallengeModal] = useState(false);
  const [challengeCount, setChallengeCount] = useState(50);
  const [importText, setImportText] = useState("");

  // Quiz state
  const [quizPool, setQuizPool] = useState([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [question, setQuestion] = useState(null);
  const [selected, setSelected] = useState(null);
  const [firstAttemptCorrect, setFirstAttemptCorrect] = useState(null);
  const [wrongSelections, setWrongSelections] = useState(new Set());
  const [score, setScore] = useState(0);
  const [streak, setStreak] = useState(0);
  const [bestStreak, setBestStreak] = useState(0);
  const [total, setTotal] = useState(0);
  const [showResult, setShowResult] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [timeLeft, setTimeLeft] = useState(0);
  const [isChallenge, setIsChallenge] = useState(false);
  const [earlyEnd, setEarlyEnd] = useState(false);
  const [earlyEndTime, setEarlyEndTime] = useState(null);
  const [animKey, setAnimKey] = useState(0);

  // Per-question timing for weakness analysis
  const [questionStartTime, setQuestionStartTime] = useState(null);
  const [questionTimes, setQuestionTimes] = useState([]);
  const quizLevelRef = useRef(1);

  const timerRef = useRef(null);

  // ─── 篩選後字數 ────────────────────────────────────────────────
  const filteredCount = filterChars(level, selectedRadicals).length;

  // ─── 部首篩選 ──────────────────────────────────────────────────
  const visibleRadicals = ALL_RADICALS.filter(r =>
    !radicalSearch || r.includes(radicalSearch)
  );

  // ─── 切換難度時重新隨機部首 ────────────────────────────────────
  useEffect(() => {
    setSelectedRadicals(randomRadicals(5, level));
  }, [level]);

  // ─── 計時器 ────────────────────────────────────────────────────
  useEffect(() => {
    if (screen !== "quiz" || showResult || isPaused) return;
    if (timerValue === 0 && !isChallenge) return; // 無限模式不倒數

    timerRef.current = setInterval(() => {
      setTimeLeft(t => {
        if (t <= 1 && timerValue > 0) {
          clearInterval(timerRef.current);
          setShowResult(true);
          return 0;
        }
        return t - 1;
      });
    }, 1000);

    return () => clearInterval(timerRef.current);
  }, [screen, showResult, isPaused, timerValue, isChallenge]);

  // ─── 開始測驗 ──────────────────────────────────────────────────
  const startQuiz = useCallback((pool, challengeMode = false) => {
    if (pool.length === 0) return;
    const q = generateQuestion(pool[0], pool, quizLevelRef.current);
    setQuizPool(pool);
    setCurrentIdx(0);
    setQuestion(q);
    setSelected(null);
    setFirstAttemptCorrect(null);
    setWrongSelections(new Set());
    setScore(0);
    setStreak(0);
    setBestStreak(0);
    setTotal(0);
    setShowResult(false);
    setIsPaused(false);
    setIsChallenge(challengeMode);
    setEarlyEnd(false);
    setEarlyEndTime(null);
    setTimeLeft(challengeMode ? 0 : timerValue);
    setAnimKey(0);
    setQuestionStartTime(Date.now());
    setQuestionTimes([]);
    setScreen("quiz");
  }, [timerValue]);

  const handleStartNormal = () => {
    const chars = filterChars(level, selectedRadicals);
    if (chars.length === 0) return;
    quizLevelRef.current = level;
    const pool = generateQuizPool(chars, Math.min(chars.length, 999));
    startQuiz(pool);
  };

  const handleStartChallenge = () => {
    quizLevelRef.current = 5;
    const pool = generateChallengePool(challengeCount);
    setShowChallengeModal(false);
    startQuiz(pool, true);
  };

  const handleImport = () => {
    const parsed = parseMarkdownImport(importText);
    if (parsed.length === 0) return;
    setImportText("");
    quizLevelRef.current = 5;
    startQuiz(parsed);
  };

  // ─── 下一題 ────────────────────────────────────────────────────
  const goNext = useCallback(() => {
    const elapsed = Date.now() - (questionStartTime || Date.now());
    setQuestionTimes(prev => [...prev, {
      char: quizPool[currentIdx]?.char,
      zhuyin: quizPool[currentIdx]?.zhuyin,
      time: elapsed,
      correct: firstAttemptCorrect,
    }]);

    const next = currentIdx + 1;
    if (next >= quizPool.length) {
      setShowResult(true);
      return;
    }
    setCurrentIdx(next);
    const q = generateQuestion(quizPool[next], quizPool, quizLevelRef.current);
    setQuestion(q);
    setSelected(null);
    setFirstAttemptCorrect(null);
    setWrongSelections(new Set());
    setAnimKey(k => k + 1);
    setQuestionStartTime(Date.now());
  }, [currentIdx, quizPool, questionStartTime, firstAttemptCorrect]);

  // ─── 選擇答案（嚴格模式）──────────────────────────────────────
  const handleSelect = (opt) => {
    if (!question) return;
    // 已經選對了就不能再點
    if (selected === question.answer) return;
    // 已經點過的錯誤選項不能再點
    if (wrongSelections.has(opt)) return;

    const isCorrect = opt === question.answer;

    if (isCorrect) {
      setSelected(opt);
      // 只有第一次就選對才計分
      if (firstAttemptCorrect === null) {
        setFirstAttemptCorrect(true);
        setScore(s => s + 1);
        setStreak(s => {
          const ns = s + 1;
          setBestStreak(b => Math.max(b, ns));
          return ns;
        });
      }
      setTotal(t => t + 1);
      // 自動跳下一題
      setTimeout(goNext, 800);
    } else {
      // 錯誤：標記此選項，不顯示正確答案
      if (firstAttemptCorrect === null) {
        setFirstAttemptCorrect(false);
        setStreak(0);
        setTotal(t => t + 1);
      }
      setWrongSelections(prev => new Set([...prev, opt]));
    }
  };

  // ─── 暫停/結束 ────────────────────────────────────────────────
  const togglePause = () => setIsPaused(p => !p);
  const endGame = (isEarly = false) => {
    clearInterval(timerRef.current);
    if (isEarly) {
      setEarlyEnd(true);
      setEarlyEndTime(formatTime(timeLeft));
    }
    // Record last question time
    if (quizPool[currentIdx] && questionStartTime) {
      const elapsed = Date.now() - questionStartTime;
      setQuestionTimes(prev => [...prev, {
        char: quizPool[currentIdx].char,
        zhuyin: quizPool[currentIdx].zhuyin,
        time: elapsed,
        correct: firstAttemptCorrect,
      }]);
    }
    setShowResult(true);
    setIsPaused(false);
  };

  // ─── 部首操作 ──────────────────────────────────────────────────
  const toggleRadical = (r) => {
    setSelectedRadicals(prev => {
      const next = new Set(prev);
      if (next.has(r)) next.delete(r); else next.add(r);
      return next;
    });
  };
  const selectAllRadicals = () => setSelectedRadicals(new Set(ALL_RADICALS));
  const clearAllRadicals = () => setSelectedRadicals(new Set());

  // ─── 弱點分析：思考時間最久前 5 字 ─────────────────────────────
  const weaknesses = [...questionTimes]
    .sort((a, b) => b.time - a.time)
    .slice(0, 5);

  // ─── 當前題目的多音字提示 ──────────────────────────────────────
  const currentItem = quizPool[currentIdx];
  const multiReadings = currentItem?.readings;

  // ═══════════════════════════════════════════════════════════════
  // RENDER
  // ═══════════════════════════════════════════════════════════════
  return (
    <div className="app">
      {/* ═══ HOME ═══ */}
      {screen === "home" && (
        <>
          <div className="header">
            <h1>漢字高手</h1>
            <div className="subtitle">RPG 魔物漢字測驗 · 108 課綱</div>
          </div>

          {/* RPG 難度選擇 */}
          <div className="level-grid">
            {LEVELS.map(lv => (
              <button
                key={lv.id}
                className={`level-btn ${level === lv.id ? "active" : ""}`}
                onClick={() => setLevel(lv.id)}
              >
                <span className="lv-emoji">{lv.emoji}</span>
                <span className="lv-name">Lv.{lv.id} {lv.name}</span>
                <span className="lv-range">{lv.desc}</span>
              </button>
            ))}
          </div>

          <div className="filter-count">
            目前篩選字數：<strong>{filteredCount}</strong> 字
          </div>

          {/* 部首選擇 */}
          <div className="radical-section">
            <div className="radical-header">
              <h4>
                部首篩選 <span className="count-badge">{selectedRadicals.size}/{ALL_RADICALS.length}</span>
              </h4>
              <span className="chip-actions">
                <button onClick={selectAllRadicals}>全選</button>
                <button onClick={clearAllRadicals}>清除</button>
              </span>
            </div>
            <input
              className="radical-search"
              placeholder="🔍 搜尋部首..."
              value={radicalSearch}
              onChange={e => setRadicalSearch(e.target.value)}
            />
            <div className="radical-chips">
              {visibleRadicals.map(r => (
                <span
                  key={r}
                  className={`radical-chip ${selectedRadicals.has(r) ? "on" : ""}`}
                  onClick={() => toggleRadical(r)}
                >
                  {r}
                </span>
              ))}
            </div>
          </div>

          {/* 時間設定 */}
          <div className="timer-section">
            <h4>⏱ 遊戲時間</h4>
            <div className="timer-grid">
              {TIMERS.map(t => (
                <button
                  key={t.value}
                  className={`timer-btn ${timerValue === t.value ? "active" : ""}`}
                  onClick={() => setTimerValue(t.value)}
                >
                  {t.label} {t.tag && <small>({t.tag})</small>}
                </button>
              ))}
            </div>
          </div>

          {/* 開始按鈕 */}
          <button
            className="start-btn"
            onClick={handleStartNormal}
            disabled={filteredCount === 0}
          >
            ⚔️ 開始測驗
          </button>

          {/* 全字庫挑戰 */}
          <button className="challenge-btn" onClick={() => setShowChallengeModal(true)}>
            <span className="crown">👑</span>
            全字庫挑戰模式
          </button>

          {/* 自訂題庫匯入 */}
          <div className="import-section">
            <h4>📋 擴充自訂題庫</h4>
            <p>貼上 Markdown 表格（欄位：漢字 | 注音 | 拼音 | 造詞 | 部首），標題列會自動略過。</p>
            <textarea
              className="import-textarea"
              placeholder="| 漢字 | 注音 | 拼音 | 造詞 | 部首 |&#10;| 貓 | ㄇㄠ | māo | 小貓,貓咪 | 犬 |"
              value={importText}
              onChange={e => setImportText(e.target.value)}
            />
            <div className="import-actions">
              <button className="btn-primary" onClick={handleImport} disabled={!importText.trim()}>
                匯入並開始
              </button>
            </div>
          </div>

          {/* 挑戰模式 Modal */}
          {showChallengeModal && (
            <div className="modal-overlay" onClick={() => setShowChallengeModal(false)}>
              <div className="modal-box" onClick={e => e.stopPropagation()}>
                <h3>👑 全字庫挑戰</h3>
                <p>打破所有部首與難度限制，從 {ALL_CHARS.length} 字中隨機出題！</p>
                <input
                  className="modal-input"
                  type="number"
                  min="5"
                  max={ALL_CHARS.length}
                  value={challengeCount}
                  onChange={e => setChallengeCount(Math.max(5, parseInt(e.target.value) || 50))}
                  placeholder="挑戰題數"
                />
                <div className="modal-actions">
                  <button className="btn-secondary" onClick={() => setShowChallengeModal(false)}>取消</button>
                  <button className="btn-primary" onClick={handleStartChallenge}>開始挑戰</button>
                </div>
              </div>
            </div>
          )}
        </>
      )}

      {/* ═══ QUIZ ═══ */}
      {screen === "quiz" && !showResult && question && currentItem && (
        <>
          {/* 暫停遮罩 */}
          {isPaused && (
            <div className="pause-overlay">
              <div className="pause-icon">⏸</div>
              <h2>已暫停</h2>
              <button className="btn-primary" onClick={togglePause}>▶️ 繼續</button>
              <button className="btn-secondary" onClick={() => endGame(true)}>結束遊戲</button>
            </div>
          )}

          <div className="header" style={{ position: "relative" }}>
            <button className="back-btn" onClick={() => endGame(true)}>←</button>
            <h1>
              {isChallenge ? "👑 全字庫挑戰" :
                question.mode === 1 ? "看字選音" :
                  question.mode === 2 ? "看音選字" : "造詞填空"}
            </h1>
          </div>

          <div className="quiz-top">
            <span className="quiz-progress">
              第 {currentIdx + 1} / {quizPool.length} 題
            </span>
            <div className="quiz-score-bar">
              {streak >= 2 && (
                <span className="streak-badge" key={streak}>🔥 {streak} 連對</span>
              )}
              <span>✓ {score}</span>
              {timerValue > 0 && !isChallenge && (
                <span className={`quiz-timer ${timeLeft <= 10 ? "warning" : ""}`}>
                  ⏱ {formatTime(timeLeft)}
                </span>
              )}
            </div>
          </div>

          <div className="progress-bar">
            <div className="progress-fill" style={{ width: `${(currentIdx / quizPool.length) * 100}%` }} />
          </div>

          <div className="quiz-card" key={animKey}>
            {question.mode === 1 && (
              <>
                <div className="prompt-label">這個字怎麼念？</div>
                <div className="prompt-char">{currentItem.char}</div>
                <div className="prompt-pinyin-hint">{currentItem.pinyin}</div>
              </>
            )}
            {question.mode === 2 && (
              <>
                <div className="prompt-label">這個注音是哪個字？</div>
                <div className="prompt-zhuyin">{currentItem.zhuyin}</div>
                <div className="prompt-pinyin-hint">{currentItem.pinyin}</div>
              </>
            )}
            {question.mode === 3 && (
              <>
                <div className="prompt-label">請選出正確的字填入空格</div>
                <div className="prompt-word">{question.wordBlank}</div>
                <div className="prompt-pinyin-hint">{currentItem.zhuyin} · {currentItem.pinyin}</div>
              </>
            )}

            {/* 多音字提示 */}
            {multiReadings && multiReadings.length > 1 && (
              <div className="multi-hint">
                <div className="multi-title">💡 此字為多音字，其他讀音：</div>
                {multiReadings
                  .filter(r => r.zhuyin !== currentItem.zhuyin)
                  .map((r, i) => (
                    <div key={i} className="multi-reading">
                      <span className="zy-highlight">{r.zhuyin}</span>
                      {" "}
                      <span className="zy-highlight">{r.pinyin}</span>
                    </div>
                  ))}
              </div>
            )}
          </div>

          <div className="options-grid">
            {question.options.map((opt, i) => {
              let cls = "option-btn";
              if (selected === question.answer) {
                // 已經答對
                cls += " disabled";
                if (opt === question.answer) cls += " correct-opt";
                else if (wrongSelections.has(opt)) cls += " wrong-opt";
                else cls += " greyed";
              } else {
                // 還沒答對
                if (wrongSelections.has(opt)) cls += " wrong-opt disabled";
              }
              return (
                <button key={i} className={cls} onClick={() => handleSelect(opt)}>
                  {opt}
                </button>
              );
            })}
          </div>

          <div className="quiz-controls">
            <button className="ctrl-btn" onClick={togglePause}>⏸ 暫停</button>
          </div>
        </>
      )}

      {/* ═══ RESULT ═══ */}
      {screen === "quiz" && showResult && (
        <>
          <div className="header" style={{ position: "relative" }}>
            <button className="back-btn" onClick={() => setScreen("home")}>←</button>
            <h1>測驗結果</h1>
          </div>

          <div className="result-card">
            <div className="result-emoji">
              {total === 0 ? "📚" :
                score / total >= 0.9 ? "🏆" :
                  score / total >= 0.7 ? "🌟" :
                    score / total >= 0.5 ? "💪" : "📚"}
            </div>
            <h2>
              {total === 0 ? "下次加油！" :
                score / total >= 0.9 ? "太厲害了！" :
                  score / total >= 0.7 ? "表現很好！" :
                    score / total >= 0.5 ? "繼續加油！" : "多練習幾次吧！"}
            </h2>
            <div className="result-score">{score} / {total}</div>
            <div className="result-detail">
              正確率 {total > 0 ? Math.round((score / total) * 100) : 0}%
              {bestStreak >= 2 && <> · 最高連對 {bestStreak} 題</>}
              {earlyEnd && earlyEndTime && (
                <><br />⏱ 提早結束，剩餘時間：{earlyEndTime}</>
              )}
              {isChallenge && <><br />👑 全字庫挑戰模式</>}
            </div>
            <div className="result-actions">
              <button className="btn-primary" onClick={() => {
                if (isChallenge) {
                  handleStartChallenge();
                } else {
                  handleStartNormal();
                }
              }}>再來一次</button>
              <button className="btn-secondary" onClick={() => setScreen("home")}>回首頁</button>
            </div>
          </div>

          {/* 弱點分析 */}
          {weaknesses.length > 0 && (
            <div className="weakness-section">
              <h4>🎯 弱點分析 — 思考最久的字</h4>
              {weaknesses.map((w, i) => (
                <div key={i} className="weakness-item">
                  <div className="weakness-char">{w.char}</div>
                  <div className="weakness-info">
                    {w.zhuyin}
                    {w.correct === false && " · ❌ 答錯"}
                    {w.correct === true && " · ✅ 答對"}
                  </div>
                  <div className="weakness-time">
                    {(w.time / 1000).toFixed(1)}s
                  </div>
                </div>
              ))}
            </div>
          )}
        </>
      )}
    </div>
  );
}
